export type Platform =
  | "twitter"
  | "linkedin"
  | "github"
  | "instagram"
  | "youtube"
  | "facebook"
  | "tiktok"
  | "reddit"
  | "twitch"
  | "medium"
  | "devto"
  | "hashnode"
  | "substack"
  | "bluesky"
  | "threads"
  | "mastodon"
  | "producthunt"
  | "dribbble"
  | "behance"
  | "stackoverflow"
  | "leetcode"
  | "geeksforgeeks"
  | "kaggle"
  | "huggingface"
  | "telegram"
  | "discord"
  | "pinterest"
  | "snapchat"
  | "figma"
  | "website";

const PLATFORM_PATTERNS: Array<{ platform: Platform; regex: RegExp }> = [
  { platform: "twitter", regex: /x\.com|twitter\.com/ },
  { platform: "linkedin", regex: /linkedin\.com/ },
  { platform: "github", regex: /github\.com/ },
  { platform: "instagram", regex: /instagram\.com/ },
  { platform: "youtube", regex: /youtube\.com|youtu\.be/ },
  { platform: "facebook", regex: /facebook\.com|fb\.com/ },
  { platform: "tiktok", regex: /tiktok\.com/ },
  { platform: "reddit", regex: /reddit\.com/ },
  { platform: "twitch", regex: /twitch\.tv/ },
  { platform: "medium", regex: /medium\.com/ },
  { platform: "devto", regex: /dev\.to/ },
  { platform: "hashnode", regex: /hashnode\.dev/ },
  { platform: "substack", regex: /substack\.com/ },
  { platform: "bluesky", regex: /bsky\.app/ },
  { platform: "threads", regex: /threads\.net/ },
  { platform: "mastodon", regex: /mastodon\.social/ },
  { platform: "producthunt", regex: /producthunt\.com/ },
  { platform: "dribbble", regex: /dribbble\.com/ },
  { platform: "behance", regex: /behance\.net/ },
  { platform: "stackoverflow", regex: /stackoverflow\.com/ },
  { platform: "leetcode", regex: /leetcode\.com/ },
  { platform: "geeksforgeeks", regex: /geeksforgeeks\.org/ },
  { platform: "kaggle", regex: /kaggle\.com/ },
  { platform: "huggingface", regex: /huggingface\.co/ },
  { platform: "telegram", regex: /t\.me/ },
  { platform: "discord", regex: /discord\.gg|discord\.com/ },
  { platform: "pinterest", regex: /pinterest\.com/ },
  { platform: "snapchat", regex: /snapchat\.com/ },
  { platform: "figma", regex: /figma\.com/ },
];

const PLATFORM_ICONS = {
  twitter: XIcon,
  linkedin: Linkedin,
  github: Github,
  instagram: Instagram,
  youtube: Youtube,
  facebook: Facebook,
  tiktok: Tiktok,
  reddit: Reddit,
  twitch: Twitch,
  medium: Medium,
  hashnode: Hashnode,
  bluesky: Bluesky,
  threads: Threads,
  dribbble: Dribbble,
  behance: Behance,
  stackoverflow: Stackoverflow,
  leetcode: Leetcode,
  geeksforgeeks: GFG,
  telegram: Telegram,
  discord: Discord,
  pinterest: Pinterest,
  snapchat: Snapchat,
  figma: Figma,
  devto: Devto,
  substack: Substack,
  mastodon: Mastodon,
  kaggle: Kaggle,
  huggingface: Huggingface,
  producthunt: LinkIcon,
  website: LinkIcon,
};

export const GetPlatformName = (url: string): Platform => {
  const match = PLATFORM_PATTERNS.find(({ regex }) => regex.test(url));
  return match?.platform ?? "website";
};

export const getPlatformIcon = (url: string) => {
  const platform = GetPlatformName(url);
  return PLATFORM_ICONS[platform] || LinkIcon;
};

export const getUsernameFromUrl = (url: string, platform: Platform): string | null => {
  try {
    if(platform === "website") return url;
    const { pathname } = new URL(url);
    const parts = pathname.split("/").filter(Boolean);

    switch (platform) {
      case "github":
      case "twitter":
      case "instagram":
      case "facebook":
      case "tiktok":
      case "threads":
      case "bluesky":
      case "dribbble":
      case "producthunt":
      case "pinterest":
      case "snapchat":
      case "kaggle":
      case "mastodon":
        return parts[0] ?? null;                    // /{username}

      case "linkedin":
        return parts[1] ?? null;                    // /in/{username}

      case "youtube":
        // /@username or /channel/... or /user/...
        if (parts[0]?.startsWith("@")) return parts[0];
        if (parts[0] === "channel" || parts[0] === "user") return parts[1] ?? null;
        return parts[0] ?? null;

      case "reddit":
        return parts[1] ?? null;                    // /u/{username}

      case "medium":
        // /@username or /{publication}
        if (parts[0]?.startsWith("@")) return parts[0];
        return parts[0] ?? null;

      case "devto":
        return parts[0] ?? null;                    // /{username}

      case "hashnode":
        return parts[0] ?? null;                    // /{username}

      case "substack":
        // {username}.substack.com
        const host = new URL(url).hostname;
        return host.split(".")[0] ?? null;

      case "stackoverflow":
        return parts[1] ?? null;                    // /users/{id}/{username}

      case "leetcode":
        return parts[1] ?? null;                    // /u/{username}

      case "geeksforgeeks":
        return parts[1] ?? null;                    // /user/{username}

      case "huggingface":
        return parts[0] ?? null;                    // /{username}

      case "twitch":
        return parts[0] ?? null;                    // /{username}

      case "telegram":
        return parts[0] ?? null;                    // /{username}

      case "discord":
        return null;                                // invite links, no username

      case "figma":
        return parts[1] ?? null;                    // /@{username}/...

      case "behance":
        return parts[0] ?? null;                    // /{username}

      case "kaggle":
        return parts[0] ?? null;                    // /{username}

      default:
        return null;
    }
  } catch {
    return null;
  }
};

